 1	import type { FC } from 'react';
 2	import { getResourceFieldValue } from 'src/components/common/FilterGroup/matchers';
 3	import { TableCell } from 'src/modules/Providers/utils/components/TableCell/TableCell';
 4	import type { CellProps } from 'src/modules/Providers/views/list/components/CellProps';
 5	
 6	import { Truncate } from '@patternfly/react-core';
 7	import { EMPTY_MSG } from '@utils/constants';
 8	
 9	/**
10	 * URLCell component, used for displaying a TableCell with a URL string.
11	 * @param {CellProps} props - The props for the component.
12	 * @returns {JSX.Element} - The rendered component.
13	 */
14	export const URLCell: FC<CellProps> = ({ data, fieldId, fields }) => {
15	  const id = fieldId as keyof typeof data;
16	  const url = getResourceFieldValue(data, id, fields) as unknown as string;
17	
18	  return (
19	    <TableCell>
20	      <Truncate content={url?.toString() ?? EMPTY_MSG} position={'middle'} />
21	    </TableCell>
22	  );
23	};

